/* cotTruyen q10 (44 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q10"]=window.__LIBQ["tien-nghich"]["q10"]||{};window.__LIBQ["tien-nghich"]["q10"]["cotTruyen"]=[{"chuong":1170,"tieuDe":"Quy Nguyên Tông","tomTat":"Văn Thú Vương của Vương Lâm phát uy áp tân vương, buộc đàn Văn Thú đỏ và lam quy phục; hai Văn Thú trắng ngang Toái Niết thà tự nổ chứ không khuất phục. Tống Lạc Hải — trưởng lão Tịch Hồn Đạo — nhân cơ hội hỗn loạn tấn công nguyên thần Vương Lâm, nhưng bị Vương Lâm dùng quy tắc chi tinh và cơn lốc xoáy ý cảnh phản kích, phun máu thảm bại, bị toàn bộ đàn Văn Thú bao vây không được tha. Cảnh chuyển sang bát giai tinh vực, đại hội so tài phân tông nghìn năm một lần của Vô Cực Tông đang diễn ra trên tu chân tinh thứ hai. Quy Nguyên Tông chưa đến mười người, hiu quạnh ở rìa phía bắc. Lữ Anh Kiệt — đệ tử tông chủ Tiên Âm Môn — khiêu khích Lữ Yên Phỉ, tuyên bố đã chuẩn bị nguyên tinh ép Quy Nguyên Tông giải tán và muốn nàng thành người Tiên Âm Môn. Lữ Yên Phỉ bình tĩnh từ chối. Lô Vân Tòng (Tử Đạo Tông) xuất hiện bênh vực, tuyên bố Tử Đạo Tông sẽ tiếp nhận nếu giải tán, đồng thời nhắc tới Lữ huynh (Vương Lâm) như hy vọng duy nhất đưa Quy Nguyên Tông thành phân tông đệ nhất, quát mắng Lữ Anh Kiệt không xứng nhắc tên Lữ huynh."},{"chuong":1171,"tieuDe":"Lý Thiến Mai","tomTat":"Tại đại hội Vô Cực Tông, Lữ Anh Kiệt (Tiên Âm Tông, tầng 6) đấu khẩu với Lô Vân Tử (tông chủ Tử Đạo Tông, tầng 5), lo ngại bị khiêu chiến như ngàn năm trước. Lô Vân Tử tuyên bố Lữ sư huynh (Vương Lâm) có thể giết Lữ Anh Kiệt dễ như giết kiến. Triệu Long — trưởng lão ngoại sự Tầm Loan Tông (tầng 7) — xuất hiện sau lưng Lữ Anh Kiệt, tuyên bố muốn kiểm chứng người họ Lữ, liếc mắt phóng kiếm quang đánh thương Lữ Yên Phỉ khi nàng xen vào bênh vực. Lô Vân Tử buộc phải cam kết chịu hậu quả nếu Vương Lâm không tới. Bất ngờ, Lý Thiến Mai — nữ tử tóc lam duy nhất Vân Hải, cảnh giới Toái Niết, Phá Thiên Tông tầng 9 — mang khí tức Toái Niết bay tới tu chân tinh từ chiến trường Văn Thú Triều, hơn mười vạn tu sĩ xôn xao. Phùng Hải cùng sáu trưởng lão Vô Cực Tông ra nghênh đón long trọng. Lý Thiến Mai không nghỉ ngơi, hỏi thẳng Phùng Hải về vị trí Quy Nguyên Tông rồi tản thần thức tìm được và bay thẳng tới, hé lộ mục đích thật sự tới đại hội là vì Quy Nguyên Tông."},{"chuong":1172,"tieuDe":"Hắn Đến Đây Sao?","tomTat":"Phùng Hải cùng sáu trưởng lão Vô Cực Tông phóng theo dấu Lý Thiến Mai gây hỗn loạn đại hội phân tông, lão già tóc đỏ tu vi Toái Niết quát Cấm Không chấn động bầu trời ổn định trật tự. Lý Thiến Mai phóng thẳng đến khu vực Quy Nguyên Tông, phớt lờ hoàn toàn Lữ Anh Kiệt đang chào hỏi và Triệu Long đang ra mắt, khiến cả hai cứng đờ bẽ bàng trước mặt vạn người. Nàng hỏi Lữ Yên Phỉ về Vương Lâm, biết trăm năm không có tin tức, lộ vẻ buồn phiền. Nghe Lữ Yên Phỉ tố cáo Lữ Anh Kiệt đe dọa giải tán Quy Nguyên Tông bắt nàng làm lô đỉnh và Triệu Long ra tay đánh thương, Lý Thiến Mai lập tức dùng tu vi Toái Niết hậu kỳ đánh tan toàn bộ thân thể Triệu Long chỉ còn nguyên thần bỏ trốn. Nàng cảnh cáo Lữ Anh Kiệt giữ mạng chờ Vương Lâm, nếu hắn không tới chính nàng sẽ lấy mệnh, đồng thời hứa cho Vô Cực Tông công đạo. Trong khi đó trên Phong Tiên Giới, Vương Lâm áo trắng tóc trắng cưỡi Văn Vương dẫn gần năm nghìn Văn Thú đỏ máu, xác nhận mục tiêu thu đủ Văn Thú đã đạt, quyết định rời đi thực hiện lời hứa với Quy Nguyên Tông."},{"chuong":1173,"tieuDe":"Sau Tàn Dạ","tomTat":"Vương Lâm ẩn thân trong đám Văn Thú tiến sâu vào Phong Tiên Giới, cảm nhận quang cảnh hoang tàn thê lương của tiên giới chỉ còn gió cô độc. Hắn hồi tưởng so sánh ba tiên giới: Vũ Giới bị phá hủy nặng nề nhất, Lôi Giới ít bị phá hơn, Phong Giới được bảo tồn đầy đủ nhất nhờ Văn Thú. Tại mảnh đại lục lớn nhất ở trung tâm, Vương Lâm phát hiện cánh cửa đá khổng lồ cao vạn trượng giống hệt cánh cửa hạt châu Thiên Nghịch huyễn hóa, chỉ khác cửa trong hạt châu không chỉ có một khung. Dùng thần thức bao phủ, hắn phát hiện cửa đá thực chất là sinh linh đã sinh ra tư tưởng, rồi rơi vào trạng thái cảm ngộ giống hệt năm xưa ngộ Tàn Dạ trên tu chân tinh Trần Đạo Tam Tử. Khí tức hắn hoàn toàn dung nhập vào cửa đá, tiêu tán khỏi mọi cảm nhận, khiến Văn Vương hoang mang bay quanh bảo vệ cùng mấy ngàn Văn Thú. Cùng lúc ở vùng cực sâu Phong Tiên Giới, một pho tượng đá hình người bí ẩn mở mắt, nói rằng cửa đá chứa chín loại pháp tắc và Vương Lâm có thể cảm ngộ được một loại."},{"chuong":1174,"tieuDe":"Chín Luồng Quy Tắc","tomTat":"Vương Lâm dung hợp với cánh cửa đá khổng lồ và nhìn thấy ký ức của nó. Thuở xưa tiên giới đầy tiên khí, vô số tiên nhân lập trận pháp vạn dặm dời bốn phía núi và đại địa xây thành Thông Thiên Môn theo ý chỉ Viễn Cổ tiên vực để nghênh đón Viễn Cổ Chân Tiên hàng lâm. Trải qua bốn vạn năm tu sửa, Viễn Cổ Chân Tiên không đến; tiên giới rơi vào đại kiếp nạn, tiên nhân kêu cứu nhưng không ai đáp. Tuyệt vọng, họ lao lên trời tự sát với lời thề nằm lại trên tiên giới. Một ngón tay khổng lồ bị hắc khí bao phủ từ bầu trời đâm xuống đập vỡ tấm ván cửa, tiên giới vỡ nát chỉ còn khung cửa. Sau kiếp nạn, khe nứt vạn trượng xuất hiện ở vị trí sâu nhất dẫn ra tinh không, hung thú mũi khổng lồ từ tinh cầu tím xâm nhập — đó chính là nguồn gốc Văn thú. Vương Lâm tỉnh lại, bay lên nóc cánh cửa khoanh chân cảm ngộ, phát hiện tám luồng quy tắc ẩn trong thiên địa vờn quanh thân thể ngăn cánh cửa ngưng tụ trong tâm thần, rồi phát hiện luồng thứ chín — dấu vết năm tháng trên cánh cửa đã dị biến thành vĩnh hằng, bản nguyên giống nhau nhưng mức độ hoàn toàn khác biệt."},{"chuong":1175,"tieuDe":"Lưu Nguyệt","tomTat":"Vương Lâm ngồi trên cánh cửa đá khổng lồ trong Phong giới suốt mười ngày, tập trung cảm ngộ loại quy tắc biến hóa thứ chín — loại mạnh nhất, ẩn trong khí tức năm tháng, bỏ qua tám loại quy tắc còn lại. Hơn năm nghìn con Văn Thú do Văn Vương cầm đầu vây quanh cánh cửa đá bảo vệ hắn, bốn con xanh đậm có khí tức ngang Tịch Niết đại viên mãn bay quanh hộ vệ. Tâm thần Vương Lâm dung hợp với cánh cửa đá, cảm nhận sự tang thương năm tháng và hồi tưởng ký ức cùng Vương Bình đi khắp sông núi. Trong tâm cảnh, biển rộng hiện ra dưới cánh cửa đá, kim quang bùng lên từ đáy biển, Vương Lâm ngộ ra bản chất tu đạo và đặt tên thần thông thứ hai là Lưu Nguyệt — năm tháng chảy xuôi vĩnh hằng, muốn dừng phải phá vỡ quá trình vĩnh hằng để xuất hiện Phương Hoa. Nhóm hơn mười tu sĩ kiệt xuất tinh vực cấp tám do Lý Nguyên Lôi dẫn đầu tiến sâu vào Phong giới, suốt gần mười ngày không gặp Văn Thú nên thu hoạch lớn chưa từng có. Khi phát hiện đám mây đỏ Văn Thú và cánh cửa đá, Lý Nguyên Lôi nhận ra bóng người áo trắng ngồi khoanh chân trên đó, liên hệ với tu sĩ từng thấy ngoài khe nứt. Một thanh niên hắc y nhận xét cánh cửa đá giống tế đàn cực kỳ quan trọng thời tiên giới chưa tan vỡ. Cả nhóm chấn động vì Văn Thú không tấn công mà bảo vệ người đó, nỗi sợ hãi còn hơn cả những người đã thấy Vương Lâm trước đó."},{"chuong":1176,"tieuDe":"Một Mạch Một Trăm Năm","tomTat":"Văn Vương rít lên điều khiển vài ngàn Văn Thú bao vây hơn mười tu sĩ do Lý Nguyên Lôi dẫn đầu đang định rút lui, cưỡng chế giữ họ trước cánh cửa đá nơi Vương Lâm đả tọa vì nghĩ chủ nhân tu luyện xong sẽ cần người thử nghiệm. Trong tâm thần, Vương Lâm đặt tên thức thần thông thứ hai là Lưu Nguyệt và vung tay kích hoạt, vô tình cuốn đám tu sĩ vào thiên địa thần thông. Lưu Nguyệt xoay ngược ký ức và tu vi mục tiêu — mỗi hơi thở tương đương một trăm năm cuộn ngược: sau mười hai hơi thở, tu vi Lý Nguyên Lôi từ Tịch Niết đại viên mãn rơi xuống Khuy Niết đại viên mãn, một nữ tu sĩ từ Đệ Nhị Bộ rơi xuống Vấn Đỉnh. Vương Lâm mở mắt minh ngộ quy tắc biến hóa, quở Văn Vương rồi vung tay áo giải phóng đám người, trả hai ngàn năm thời gian về cơ thể họ. Ở vị trí rất sâu trong Phong giới, lão già hóa đá hai mắt đột nhiên sáng rực, đánh giá Vương Lâm không đơn giản."},{"chuong":1177,"tieuDe":"Nghịch Văn Thú","tomTat":"Sau sự kiện cánh cửa đá, nhóm Lý Nguyên Lôi kính sợ Vương Lâm sâu đậm, đồng loạt cúi đầu rồi phóng đi mang theo ấn tượng về hình bóng tóc trắng áo trắng cùng hai chữ Lưu Nguyệt. Vương Lâm suy ngẫm về thức thần thông thứ hai Lưu Nguyệt, nhận ra chưa hoàn toàn nắm bắt nhưng nếu có thêm thời gian có thể nắm quy tắc năm tháng và vĩnh hằng, quyết định ba ngày sau rời Phong giới xử lý chuyện Quy Nguyên Tông. Hắn phong bế toàn thân khí tức bằng nhiều tầng cấm chế rồi dẫn Văn Vương cùng mấy ngàn Văn Thú tiến vào vùng sâu nhất Phong giới. Trên đường gặp hai Văn Thú tím khí tức Toái Niết đại viên mãn sắp tiếp cận Thiên Nhân Đệ Nhất Suy. Ở trung tâm, Vương Lâm phát hiện ba đại lục trôi nổi được chín đại lục bảo vệ bao quanh — thực chất là tập hợp mười vạn đến năm mươi vạn Văn Thú ngưng tụ, với năm tầng màu sắc phân bậc. Trên bầu trời ba đại lục trung tâm xuất hiện khe nứt khổng lồ, bên trong có Văn Thú vài vạn trượng thò nửa người ra gào thét, toàn Phong Tiên giới suýt tan vỡ, tất cả Văn Thú quỳ lạy. Vương Lâm tái mặt ra lệnh rút lui, nhưng Văn Vương xoay người hướng về Văn Thú khổng lồ gầm rống kinh thiên, thể hiện tôn nghiêm không cam lòng khuất phục, tiếng gầm vang vọng khắp Phong giới."},{"chuong":1178,"tieuDe":"Văn Vương Biến Dị","tomTat":"Văn Vương của Vương Lâm gầm rống khiêu chiến, bùng lên khát vọng dữ dội muốn hấp thu dòng máu thuần khiết từ Văn Thú khổng lồ trong khe nứt. Cuộc chiến chỉ dành cho Văn Thú từ cấp tím trở lên, hàng ngàn Văn Thú tím (khí tức Toái Niết đại viên mãn) xông tới tấn công. Vương Lâm bày ra tu vi Đệ Nhị Bộ, phóng đại thân Cổ Thần lên vài trăm trượng, dồn toàn bộ lực lượng Cổ Thần, ý cảnh quy tắc tinh, sấm sét, lửa lam cùng tiên thuật Bạch Phàm vào Tam Xoa Kích ném một đòn mở đường, ném Văn Vương xuyên qua vòng vây. Văn Vương bị thương nặng nhưng xảy ra biến dị kinh thiên: máu chảy ra có màu vàng thay vì đỏ, bên ngoài thân thể xuất hiện hình bóng hư ảo Văn Thú vài vạn trượng. Tất cả Văn Thú mọi cấp bậc kể cả Văn Thú khổng lồ trong khe nứt đều chấn động kính sợ. Thân Vương Lâm cũng lóe kim quang, đám Văn Thú tránh sạch. Vương Lâm mơ hồ giác ngộ vì sao Chu Tước Tinh chỉ có duy nhất một con Văn Thú. Văn Vương hóa lưu tinh lam sắc xông về phía khe nứt, Văn Thú khổng lồ giãy giụa kịch liệt."},{"chuong":1179,"tieuDe":"Thu Hoạch","tomTat":"Văn Vương của Vương Lâm tấn công Văn Vương khổng lồ vài vạn trượng đang mắc kẹt nửa thân trong khe nứt, dùng vòi hút máu hai lần khiến vết thương lành hẳn và uy áp tăng vọt. Dưới uy áp mới, đại quân Văn Thú đa sắc gồm hơn vạn đỏ, hơn ngàn xanh, trăm trắng, hai tím và trăm vàng chủ động theo Văn Vương của Vương Lâm — thu hoạch lớn nhất tại Phong Tiên giới. Văn Vương vạn trượng phá khe nứt thoát ra hoàn toàn, tức giận dẫn hơn trăm vạn Văn Thú che rợp trời truy kích. Vương Lâm thu nhỏ thân thể cầm Tam Xoa Kích, vừa phóng ra rìa Phong Tiên giới vừa bố trí trận pháp cấm chế ngăn cản. Tình thế nguy cấp, Vương Lâm dung hợp tâm thần với hồn phách Thiên Vận Tử bị phong ấn trong nguyên thần, ném Nghịch Thiên Châu triệu hồi Nghịch Hành giả — la bàn khổng lồ ngàn trượng bảy màu xoay tròn chặn đám Văn Thú, thạch châu tan vỡ tiêu hao. Sau khi tách hồn phách, vẻ mặt tái nhợt do vết thương chưa khôi phục, tiếp tục dùng hắc long và trận pháp cản đường. Còn vài canh giờ nữa đến vết nứt thông ra tinh vực Vân Hải, nhưng phía sau trăm dặm là trăm vạn Văn Thú và Văn Vương vạn trượng đang ồ ạt truy đuổi."},{"chuong":1180,"tieuDe":"Mộc Băng Mi","tomTat":"Vương Lâm dùng thần thông tạo không gian trữ vật thứ hai, xé hư không mở khe nứt ngàn trượng rồi dùng sấm sét Quy tắc chi tinh cùng lửa lam ổn định, ném tiên ngọc và nguyên tinh vào bên trong. Hơn vạn Văn Thú bao gồm Văn Vương, hai con tím và Văn Thú vàng tuôn vào, Văn Vương tiến vào cuối cùng quay đầu nhìn Vương Lâm rồi biến mất. Vương Lâm lần đầu tiên thi triển Súc Địa Thành Thốn tại Vân Hải tinh vực, dung nhập thiên địa bước một bước từ sâu trong Phong Tiên giới tới khe nứt ra vào rồi nhảy vào rời Tiên giới. Khoảnh khắc hắn rời đi, ở sâu trong Phong giới trên ba mảng đại lục được bảo vệ, mắt bức tượng đá lão già bùng sáng phát lời yêu cầu sau này Vương Lâm phải giúp lại. Trở về tinh vực cấp tám, Vương Lâm phóng về Vô Cực Tông, tự đánh giá lực lượng Văn Thú đã đủ để đối mặt Thác Sâm nếu vết thương khỏi. Tại tinh cầu Vô Cực Tông, đại hội phân tông cấp năm đang diễn ra, Tử Đạo Tông dưới sự dẫn dắt của Lô Vân Tòng quét ngang đánh dọc không đối thủ. Trên đài cao nhất, Mộc Băng Mi và Vương San San ngồi bên cạnh lão già áo trắng tông chủ phân tông, khi nhìn hình bóng cô độc Lô Vân Tòng nàng lại nhớ đến một người đàn ông khác. Mộc Băng Mi trầm tư kể lộ trình tu đạo người đó chưa hai ngàn năm đã Tịnh Niết sơ kỳ, cả đời ngộ đạo khám phá sinh tử, khẳng định Lô Vân Tòng nói về đạo không bằng và chiến đấu sinh tử cũng chỉ chuốc lấy thất bại."},{"chuong":1181,"tieuDe":"Tung Hoành Vô Cực (1)","tomTat":"Mộc Băng Mi kể lại ấn tượng về một tu sĩ Tịch Niết sơ kỳ năm xưa trước mặt tông chủ Vô Cực Tông và nam tử họ Trứu, từ chối tiết lộ tên và nói gặp được chưa chắc may mắn. Vương San San giới thiệu Lý Thiến Mai là thiên chi kiêu nữ Vân Hải tu vi Toái Niết đại viên mãn, hiện đang ngồi ở vị trí Quy Nguyên Tông. Phùng Hải thuật lại sự kiện Lý Thiến Mai phá hủy thân thể Triệu Long bảo vệ Quy Nguyên Tông, đồng thời điều tra ra Lữ Tử Hạo là sư tổ Quy Nguyên Tông, họ hàng Lữ Yên Phỉ, cả đời thích luyện đan, mất tích nhiều năm. Trên đài tỷ thí, Lô Vân Tòng chỉ bước sáu bước đã đánh bại tông chủ phân tông đối diện bằng ý cảnh dung hợp trong bước chân. Sau đó Lô Vân Tòng bất ngờ tuyên bố từ chối tỷ thí với Quy Nguyên Tông vì không công bằng, bùng tu vi Tịch Niết nói muốn chứng đạo với Lữ Tử Hạo. Lữ Yên Phỉ dù tái nhợt vẫn kiên định lên đài đại diện Quy Nguyên Tông, trong lòng tin chắc Lữ Tử Hạo sẽ đến. Danh tiếng Lữ Tử Hạo đạt đỉnh phong, cuối cùng chính tông chủ Vô Cực Tông đích thân lên tiếng gọi Lô Vân Tòng và Lữ Yên Phỉ đến gặp, tỏ ra rất hứng thú với người thần bí này."},{"chuong":1182,"tieuDe":"Tung Hoành Vô Cực (2)","tomTat":"Lô Vân Tòng và Lữ Yên Phỉ bay lên khán đài bái kiến tông chủ Vô Cực Tông cùng chư trưởng lão. Lô Vân Tòng kể lại toàn bộ sự kiện gặp Lữ Tử Hạo (Vương Lâm): con trai bị giết, ba vấn đề luận đạo với Lý Thiến Mai, và vòng tròn thiên địa. Tông chủ khen ngợi sự minh ngộ vượt vòng thiên địa, tính toán Lữ Tử Hạo thuộc phân tông Quy Nguyên Tông nên cũng là đệ tử Vô Cực Tông, quyết định hoãn tỷ thí Quy Nguyên Tông để chờ hắn. Lô Vân Tòng dùng ngọc giản tạo hình ảnh hư ảo tóc trắng áo trắng của Vương Lâm, khiến hai trưởng lão nhận ra và Mộc Băng Mi chấn động đau thương. Lý Thiến Mai phóng đến đại hội với sát khí trăm năm chém giết, nhìn hình ảnh hư ảo mà run rẩy — suốt trăm năm mỗi lần bị thương đều nghĩ đến Vương Lâm, đến đại hội chính vì cố chấp muốn gặp lại hắn. Ngô trưởng lão tiết lộ từng thấy Vương Lâm giết rết lửa cấp mười một và đánh trọng thương mãnh thú cấp mười hai, thừa nhận không phải đối thủ. Trưởng lão thứ hai kể Vương Lâm từ tinh vực cấp năm phóng ra, thi triển Dịch Linh Ấn phá hủy Man Hoang đại lục buộc tông phái nhường đường, tiến thẳng tinh vực cấp tám, khiến toàn bộ đám người kinh hoàng."},{"chuong":1183,"tieuDe":"Tung Hoành Vô Cực (3)","tomTat":"Mộc Băng Mi nghe tin về Vương Lâm (Lữ Tử Hạo), cười khổ thầm nghĩ hắn đến đâu cũng gây chuyện kinh người. Lý Thiến Mai hiểu rõ đối phương không quên hẹn ước trăm năm, được Vương San San giới thiệu gặp mặt Mộc Băng Mi lần đầu, hai nữ nhìn thẳng vào nhau. Viên Phỉ, đại đệ tử Cự Linh Tông cấp sáu tu vi Toái Niết sơ kỳ, nổi danh trong tỷ thí bằng sự độc ác rồi thách thức cả Lý Thiến Mai và Lô Vân Tòng. Tông chủ Vô Cực Tông thay đổi nhìn nhận về Lữ Tử Hạo, không còn coi là vãn bối mà là người cùng thế hệ, ra lệnh Lô Vân Tòng và Lữ Yên Phỉ lên đài hoàn thành tỷ thí cấp năm không chờ thêm. Triệu Long chỉ còn nguyên thần cùng đại trưởng lão và tông chủ Tầm Loan Tông thề giết Lữ Tử Hạo. Lý Thiến Mai thầm quyết định nếu Quy Nguyên Tông giải tán sẽ mang tất cả mọi người về Phá Thiên Tông. Lữ Yên Phỉ kiên quyết lên đài tỷ thí, vừa thi triển pháp quyết thì lực lượng kỳ dị từ trên trời can thiệp khiến vòng xoáy nguyên lực thoát kiểm soát, thiên địa biến sắc sấm sét bao phủ, một hình bóng trắng tóc trắng tung bay xuất hiện trên đỉnh trời — Vương Lâm đã đến."},{"chuong":1184,"tieuDe":"Tung Hoành Vô Cực (4)","tomTat":"Vương Lâm giáng lâm đại hội tông phái giữa mạng lưới sấm sét vô tận, gây chấn động gần mười vạn tu sĩ. Tông chủ Vô Cực Tông (Thiên Nhân Đệ Nhất Suy) nhìn thấy trên mi tâm Vương Lâm ẩn giấu luồng quy tắc mới vượt ngoài thiên địa, tự nhận nếu giao chiến không tin sẽ thắng. Lô Vân Tòng ôm quyền tuyên bố Tử Đạo Tông chấp nhận thua cuộc, ý cảnh đạo niệm của hắn xuất hiện dấu hiệu tan vỡ trước mặt Vương Lâm. Lữ Yên Phỉ khóc sung sướng, được Vương Lâm đưa ra khán đài an toàn. Vương Lâm tuyên bố bắt buộc tất cả phân tông cấp năm, sáu, bảy nhường bước cho Quy Nguyên Tông trở thành đệ nhất. Hắn đánh vỡ thân thể tông chủ Tiên Âm Môn bằng cuồng phong, sau đó dùng một chỉ Thiên Vận giết chết Lữ Anh Kiệt cùng sư tôn, thân thể tan vỡ nguyên thần tiêu tán, tuyên bố kẻ cứu sẽ cùng tội. Cuối chương Vương Lâm xoay người phóng về phía Tầm Loan Tông truy sát Triệu Long."},{"chuong":1185,"tieuDe":"Tung Hoành Vô Cực (5)","tomTat":"Chương giải thích cơ chế thần thông Một Chỉ Thiên Vận: dung hợp linh hồn Thiên Vận Tử, tiêu hao hồn phách Nghịch Hành giả cùng nguyên lực Vương Lâm, uy lực kém bản gốc. Vương Lâm bước tới khu vực Tầm Loan Tông uy hiếp, tông chủ và đại trưởng lão tự biết không phải đối thủ, chủ động tránh đường. Triệu Long tuyệt vọng thiêu đốt nguyên thần hóa lưu tinh tự bạo, tu vi tăng lên Toái Niết đỉnh phong rồi lao tới, nhưng Vương Lâm trực tiếp vung chân đá nát nguyên thần khiến hắn chết. Trưởng lão Vô Cực tông Phùng Hải xuất thân từ Tầm Loan Tông xông ra cầu tình nhưng bị sát khí ép dừng bước, Vương Lâm bảo lời của lão đã chậm. Mộc Băng Mi chua xót so sánh cảnh ngộ bản thân với Lý Yên Phỉ, nhận ra mình mãi mãi một mình gánh chịu. Vương Lâm tuyên bố đại diện Quy Nguyên Tông khiêu chiến tất cả phân tông cấp sáu, bảy và tám. Cuối chương, Vân San từ Thanh Vân Đạo cấp bảy bình thản đứng ra nhận lời thách đấu."},{"chuong":1186,"tieuDe":"Tung Hoành Vô Cực (6)","tomTat":"Đàn ông áo xanh thuộc Thanh Vân Tông (Toái Niết hậu kỳ), một trong ba đệ tử được Vô Cực tông bồi dưỡng trọng điểm, bước lên đài thách đấu Vương Lâm và thi triển Hổ Hồn Cửu Chuyển triệu mãnh hổ chín đầu. Vương Lâm triệu lửa lam phá ba đầu mãnh hổ, sau đó thi triển Thiên địa chi hỏa thu hút toàn bộ hỏa nguyên lực trong trường khiến mọi tu sĩ hệ hỏa mất kiểm soát, trưởng lão hệ hỏa Vô Cực tông suýt mất hỏa nguyên thần. Vương Lâm dùng Định khống chế đối thủ rồi ba chỉ đánh văng khỏi đài, đối phương phun máu thảm bại và thừa nhận bị hạ thủ lưu tình. Dù bề ngoài thản nhiên, nội thương Vương Lâm nặng thêm do cưỡng chế toàn lực. Các trưởng lão và tông chủ Vô Cực tông đều kinh hoàng trước sức mạnh của hắn. Sau đó Đỗ Lâm (Tử Tùng Cốc) và Doãn Hồ (Thiên Âm Tông) cùng bước lên thách đấu, Vương Lâm bảo cả nhóm cùng lên một lúc rồi đẩy tay phải xuống đài cao khiến cả tu chân tinh chấn động, bùng ra khí tức tang thương. Tu sĩ kinh hoàng hô lên nhận ra đây là rút lực linh hồn."},{"chuong":1187,"tieuDe":"Tung Hoành Vô Cực (7)","tomTat":"Vương Lâm đứng trên đài cao thi triển thuật rút hồn lần thứ ba (thực chất lần thứ hai chính thức), vung trảo rút linh hồn tu chân tinh ngưng tụ thành quả cầu trắng trên tay phải. Toàn bộ tu chân tinh bị ảnh hưởng nghiêm trọng: cỏ cây héo rũ, núi chuyển xám, sông cạn kiệt, biển phía tây sôi trào hóa hơi nước, mây đen phủ trời, sấm sét gầm rú, mưa lớn ào ào. Các tu sĩ đại thần thông cấp bảy nhận ra đây là thuật rút hồn — thần thông đỉnh cao từ ba giới, ở Vân Hải chỉ là truyền thuyết do Phong Tiên giới tan vỡ nên thất truyền. Đỗ Lâm và Doãn Hồ xông lên khiêu chiến, bị Vương Lâm ném quả cầu linh hồn đánh trọng thương cùng lúc, cả hai chỉ sống nhờ hắn không có sát tâm. Phùng Hải lần đầu lộ vẻ sợ hãi nhưng lập tức cười lạnh, nhớ đến việc Vương Lâm giết Triệu Hải khiến Tầm Loan Tông mất mặt, và tiết lộ tông chủ đời đầu Tầm Loan Tông hiện là thái thượng trưởng lão Vô Cực tông, tính tình cổ quái, chắc chắn sẽ không vui. Tông chủ Vô Cực tông cũng vẻ mặt biến đổi, nhìn chằm chằm Vương Lâm."},{"chuong":1188,"tieuDe":"Tung Hoành Vô Cực (8)","tomTat":"Đỗ Lâm và Doãn Hồ lần lượt thất bại thảm hại trước thần thông rút hồn của Vương Lâm, ôm quyền bỏ đi trong mưa. Vương San San nhận ra thuật rút hồn thuộc Đệ Tam Bộ, là một trong bốn đại thần thông tự ngộ cùng Súc Địa Thành Thốn. Vương Lâm thách đấu toàn bộ tinh vực cấp bảy nhưng không ai dám ra, hình bóng áo trắng khắc sâu vào lòng vạn tu sĩ. Tông chủ Vô Cực tông bùng uy áp Thiên Nhân Suy Kiếp đối đầu, sấm sét phải tránh, mưa ngừng giữa trời, ánh mắt hai người đối công gây nổ vang trời đất. Mộc Băng Mi lộ tu vi Toái Niết thi triển ấn ký truyền thừa thánh nữ Côn Hư triệu Lưu Ly Bảo Bình hư ảo phá uy áp, nhưng vết thương nặng thêm. Lý Thiến Mai bùng sát khí lẫn yêu khí, lộ khối ngọc giản do người Yêu Tông tặng. Vương Lâm ngăn cả hai, tuyên bố từng chiến đấu với Thiên Nhân Đệ Nhất Suy, kim quang bùng phát đối kháng uy áp, đề xuất đại diện Quy Nguyên Tông tham chiến đại hội cấp tám đổi công đạo. Thái thượng trưởng lão Vô Cực tông xuất hiện trong luồng cầu vồng, thách Vương Lâm tiếp một thức thần thông, Vương Lâm kim quang toàn thân bùng phát, hai mắt hóa vàng chuẩn bị nghênh chiến."},{"chuong":1189,"tieuDe":"Tung Hoành Vô Cực (9)","tomTat":"Lão già tóc trắng áo xám từ Vô Cực tông xuất hiện — siêu cấp cường giả đã hoàn toàn vượt Thiên Nhân Đệ Nhất Suy, toàn thân bao phủ vầng sáng quy tắc màu đỏ máu. Lão thi triển mạng lưới sơ quy tắc bao phủ thiên địa nhằm cưỡng bức Vương Lâm khuất phục, không muốn giết mà muốn dạy bảo. Vương Lâm lần đầu tiên chủ động thi triển thần thông Tàn Dạ nhờ thần thông thứ hai mới minh ngộ giúp kích hoạt, cộng với tu vi tăng mạnh sau nuốt Đạo quả và quy tắc tinh ngưng tụ mi tâm. Hắn dám hao tốn toàn bộ nguyên lực vì có Văn Thú bảo vệ tính mạng. Thiên địa chìm vào bóng tối, mặt biển hư ảo xuất hiện, mặt trời bình minh nhú lên xé toạc tất cả — Tàn Dạ phá vỡ hoàn toàn mạng lưới sơ quy tắc. Lão già phải liên tục lui về phía sau chống đỡ. Vương Lâm phản kích bằng câu thách đấu nghịch chuyển, trấn áp toàn bộ tu sĩ và trưởng lão Vô Cực tông."},{"chuong":1190,"tieuDe":"Tung Hoành Vô Cực (10)","tomTat":"Lão già tóc trắng (cường giả Thiên Nhân Đệ Nhất Suy, Vô Cực Tông) phá giải được Tàn Dạ sau khi lui ra vài ngàn trượng, bùng tu vi phản công lao về phía Vương Lâm. Vương Lâm dùng quy tắc chi tinh hấp thu nguyên lực thiên địa, triệu hoán cánh cửa đá Lưu Nguyệt từ Phong Tiên giới (đã dung nhập tâm thần) — cửa đá khổng lồ lao lên từ mặt biển hư ảo, đài cao chiếm gần nửa tu chân tinh tan vỡ thành đá vụn. Vương Lâm đứng trên đỉnh cửa đá thi triển thần thông Lưu Nguyệt, tác động ký ức lão già — mỗi hơi thở lật lại 100 năm, tu vi theo đó thụt lùi. Ký ức ba ngàn năm trước lộ ra cảnh đệ tử yêu nhất chết trận trong khe nứt Yêu Tông, bốn-năm ngàn năm trước là cảnh vùng vẫy chống Thiên Nhân Suy Kiếp. Lão gầm rống tuyên bố tu đạo mười vạn chín ngàn năm rồi phun máu vùng thoát. Huyết điểm trên mi tâm hơn mười vạn tu sĩ bay về dung nhập vào lão. Lão hoàn toàn kinh hoàng trước Vương Lâm, mọi ý nghĩ muốn dạy bảo biến mất. Vương Lâm nhận ra Lưu Nguyệt và Đạo Tiên Thuật có kết quả tương tự, đồng thời xác nhận với tu vi hiện tại rất khó giết Thiên Nhân Đệ Nhất Suy trừ khi vứt bỏ phong ấn đạt Toái Niết."},{"chuong":1191,"tieuDe":"Ẩn Hiện Sinh Tử Kiếp","tomTat":"Vương Lâm thừa nhận Lưu Nguyệt mới cảm ngộ chưa hoàn mỹ, nguyên lực gần cạn, chỉ nghịch chuyển được năm nghìn năm, nhưng đủ hù dọa đối phương. Gần mười vạn tu sĩ kinh hoàng, danh tiếng Lữ Tử Hạo và Quy Nguyên Tông nổi khắp Vân Hải tinh vực. Lão già tóc trắng công khai nhận thua, tông chủ Vô Cực Tông chủ động đề xuất nâng Quy Nguyên Tông từ tinh vực cấp năm lên cấp bảy, Vương Lâm đồng ý và đặt điều kiện đổi vật phẩm chữa thương bí mật để xuất chiến đại hội cấp tám. Phùng Hải tiêu tan oán hận, Lữ Yên Phỉ nhớ lại lời sư tôn mắt bùng sáng, Lô Vân Tòng cay đắng nhận ra khoảng cách, Lý Thiến Mai gặp lại người trong mộng, Mộc Băng Mi xác nhận đã thành xa lạ. Vương San San bí mật khắc hình ảnh trận chiến vào ngọc giản truyền về cho sư tôn Thần Tông, tác giả hé lộ sư tôn sẽ chấn động. Tông chủ ra lệnh phong tỏa tin tức, giữ tu sĩ lại trước đại hội cấp tám. Ba người bay tới tu chân tinh trụ sở chính Vô Cực Tông, dọc đường thái thượng trưởng lão giới thiệu 372 khe nứt không gian. Cuối cùng xuất hiện ngọn núi chọc trời bùng ra tiên khí mang ý cảnh kiếm đạo, Vương Lâm nhìn thấy liền tâm thần chấn động ầm ầm."},{"chuong":1192,"tieuDe":"Sát Kiếp Đến Từ Thần Tông","tomTat":"Tông chủ và thái thượng trưởng lão Vô Cực Tông đưa Vương Lâm lên ngọn núi Lỗ Túc — trụ sở chính tông. Vương Lâm nhận ra ngọn núi thực chất là Tam Xoa Kích do vương tộc Cổ Thần phế bỏ cả tinh cầu để luyện hóa rồi ném đi, khí tức Cổ Thần nồng đậm nhưng đã yếu dần theo thời gian. Nhờ hấp thu khí tức Cổ Thần từ ngọn núi, tinh điểm thứ sáu trên mi tâm hắn (đã vỡ tan trước đây) bắt đầu ngưng tụ trở lại với tốc độ cực nhanh. Hắn suy đoán tinh điểm dùng luyện kiếm có thể thuộc Cửu Tinh Vương Tộc. Tông chủ Vô Cực Tông đồng ý san sẻ Cực Âm Hồn (cống phẩm Thần Tông) cho Vương Lâm chữa thương, Vương Lâm hứa toàn lực chiến đấu trong đại hội phân tông cấp tám. Phùng Hải đưa Quy Nguyên Tông vào đình viện cấp bảy, Lý Thiến Mai và Mộc Băng Mi ở hai nơi khác nhau cùng đợi Vương Lâm trở về dưới trời đêm. Tại trung tâm tinh vực cấp chín, đồng tử tóc bạc Thần Tông sau khi loại trừ liên tục chỉ còn Lữ Tử Hạo, nhận thêm ngọc giản tình báo từ gián điệp Vương San San trong Vô Cực Tông, bùng ra khí tức bản nguyên tương đương Lỗ Phu Tử, quyết tâm truy sát bằng mọi giá."},{"chuong":1193,"tieuDe":"Ta Đã Trở Lại","tomTat":"Thủy Đạo Tử độc thoại trong cung điện Thần Tông, tiết lộ năm xưa lão cùng Chưởng Tôn và Diệu Âm Đạo Tôn hợp lực phản bội giết chủ nhân, có tu sĩ thần bí từ Viễn Cổ Tiên Vực trợ giúp, sau đó lão tiếp quản Thần Tông. Vài tháng trước lão cảm nhận được khí tức chủ nhân, sống trong sợ hãi và điên cuồng điều tra, nghi ngờ Tử Hạo chính là chủ nhân chuyển thế vì hắn sử dụng Định Thân Thuật, một Viễn Cổ tiên thuật bảy tầng mà trên đời chỉ có chủ nhân, Thanh Sương và lão nắm giữ. Thủy Đạo Tử quyết định tế luyện chín mặt Vạn Cổ Luân Hồi Kính để bày Luân Hồi đại trận bẫy đối phương rồi mới hành động. Tại Vô Cực Tông, Vương Lâm ngồi trên đỉnh núi Lỗ Túc nói chuyện phiếm với tông chủ và thái thượng trưởng lão, lén lút hấp thu khí tức Cổ Thần khiến tinh điểm Cổ Thần thứ sáu trên mi tâm tái xuất hiện thành vòng xoáy yếu nhược, đồng thời nhận Cực Âm Hồn tinh thuần trong lá cờ sáu mặt theo thỏa thuận. Khi khí tức Cổ Thần sắp gây biến động thiên địa, Vương Lâm vội cáo từ và hẹn năm ngày sau xuất chiến đại hội phân tông cấp tám; tông chủ Vô Cực Tông phát hiện nguyên lực thiên địa quanh núi đã biến hóa bất thường nên triệu tập toàn bộ thái thượng trưởng lão bàn bạc. Vương Lâm trở về đình viện Quy Nguyên Tông, dưới ánh trăng hạ xuống trước mặt Lý Thiến Mai nói một câu ta đã trở về, bóng hai người nhập vào nhau rồi tách ra, cả hai cùng đứng lặng trầm mặc."},{"chuong":1194,"tieuDe":"Cá Và Chim","tomTat":"Vương Lâm đối diện Lý Thiến Mai dưới ánh trăng trong sân nhỏ, trầm mặc vì không biết nói gì. Hắn tự nhận rõ lòng mình đã chết, chỉ còn Lý Mộ Uyển, nhớ lại lời hứa duy nhất với nữ nhân. Lý Thiến Mai cảm ơn bút kim sắc đã làm bạn trăm năm cô độc trên chiến trường, thông báo vài ngày nữa sẽ phải rời đi và sợ mãi mãi không trở về. Nàng kể thân thế cô nhi tóc xanh kỳ lạ, tu vi nhờ Phá Thiên Tông ban, nhưng giấu Vương Lâm chuyện chịu áp lực khổng lồ khi rời chiến trường và mất cơ hội vào Yêu Tông. Vương Lâm lấy vòng tay nàng từng tặng ra định trả lại vì nó đã cứu mạng hắn trong thế giới bảy màu, nhưng Lý Thiến Mai vui mừng từ chối nhận, bảo hắn giữ rồi xoay người về phòng. Hắn hồi tưởng cảnh Thiên Nghịch kiếp trước: mình hóa cánh chim bị con cá dưới sông thu hút — ẩn dụ khoảng cách thiên địa giữa hai người. Cuối chương Vương Lâm nhìn ra ngoài đình viện thấy Liễu Mi đứng nhìn hắn với gương mặt phức tạp hiu quạnh, hồi tưởng về Hằng Nhạc Phái Chu Tước Tinh nơi Liễu Mi lần đầu nhìn thiếu niên Vương Lâm."},{"chuong":1195,"tieuDe":"Ta Hiểu","tomTat":"Vương Lâm tái ngộ Mộc Băng Mi trong đình viện Vân Hải Thần Tông, đã buông bỏ mọi ân oán trước đây. Mộc Băng Mi kể tin kinh hoàng: Thác Sâm đã thoát tù ngục, đánh tan đại quân La Thiên, phá tinh vực Thi Âm Tông khiến gần sụp đổ, đánh bại Thanh Long Thánh Hoàng tại Tứ Thánh Tông (sống chết không rõ), hủy diệt hoàn toàn Côn Hư cảnh. Toàn bộ lực lượng Liên Minh Tu Chân tan rã, nhưng cơ quan đầu não vẫn còn vì lý do bất minh. Vũ Tiên giới không bị phá nhờ Thanh Lâm ngăn cản Thác Sâm, hai bên dường như có hiệp ước. Mộc Băng Mi thoát chết nhờ quản gia tiên sinh hy sinh, thân thể từng tan vỡ phải ngưng tụ lại, tu vi thụt lùi, đến Vân Hải nhờ nhân tình cũ của thánh nữ Côn Hư đời trước. Vương Lâm phát hiện Thác Sâm đã cài ký hiệu Cổ Thần lên mi tâm Mộc Băng Mi, dùng huyết mạch Cổ Thần hút sạch dấu ấn — khí tức bị hấp thu vào vòng xoáy tinh điểm thứ sáu khiến nó vững chắc hơn. Vương Lâm phân tích Thác Sâm đã phá đại trận Phong giới đi ra Ngoại giới. Tại Thái Cổ Tinh Thần ngoài Ngoại giới, Thác Sâm vừa hủy diệt tộc Thái Cổ thứ chín, đột nhiên cảm nhận ký hiệu bị kích hoạt, xác nhận Vương Lâm ở Nội giới nhưng không đủ thực lực mở đại trận Phong giới quay lại trong thời gian ngắn."},{"chuong":1196,"tieuDe":"Kinh Biến!","tomTat":"Mộc Băng Mi đứng dưới ánh trăng nói lời từ biệt Vương Lâm, tự nhận mình chính là Liễu Mi — mẹ của Vương Bình — và nguyện rằng khi thoát khỏi xiềng xích Côn Hư sẽ cùng Vương Bình luân hồi đời đời kiếp kiếp để làm một người mẹ thật sự. Đạo tâm Thiên Huyễn Vô Tình Đạo của nàng vốn có vết nứt vì thua Liễu Mi, nay nhờ đối mặt thay vì né tránh mà dần viên mãn, hình bóng Vương Lâm trở thành ký hiệu khắc lên đạo tâm. Ba ngày sau, Mộc Băng Mi cùng Vương San San rời Vô Cực Tông về Thần Tông bế quan, còn Lý Thiến Mai nhận ngọc giản triệu tập khẩn cấp từ sư tôn Phá Thiên Tông với lời lẽ nghiêm khắc chưa từng có, vội vã truyền tống trở về. Ngay trước lúc Vô Cực Tông xuất phát dự đại hội phân tông cấp tám, một lão già tu vi Thiên Nhân Suy Kiếp mang ngọc giản Thần Tông tới, chỉ một câu ý chỉ hủy bỏ đại hội khiến tông chủ và hai thái thượng trưởng lão tức giận nhưng đành khuất nhục chấp nhận. Vương Lâm liên kết mọi dấu hiệu bất thường, cảm nhận Vân Hải tinh vực sắp có biến cố kinh thiên, lập tức đưa Quy Nguyên Tông rút về tinh vực cấp năm rồi vào mật thất kết hợp Thiên Vận Tử để cưỡng chế thôi diễn nhìn ra tương lai. Cùng lúc đó, Lý Thiến Mai vừa truyền tống đến Phá Thiên Tông liền kinh hoàng phát hiện ba trưởng lão đã bày trận pháp vây khốn truyền tống trận, sư tôn nàng phá bế quan vạn năm đích thân ngồi trước trận, ra lệnh nàng không được rời nửa bước trong ba tháng."},{"chuong":1197,"tieuDe":"Một Đường Sinh Cơ","tomTat":"Mạch nước ngầm từ Thần Tông lan ra khắp Vân Hải tinh vực gây biến cố: Lý Thiến Mai bị tông môn vây khốn ba tháng không cho ra ngoài, sư tôn bế quan vạn năm hiện thân ngăn cản; Mộc Băng Mi cùng Vương San San về Thần Tông bị hạn chế tự do, đại hội phân tông cấp tám bị hủy, người nắm quyền cao nhất là đại trưởng lão Thủy Đạo Tử. Trên Mạc La đại lục, Lữ Yên Phỉ cùng đệ tử Quy Nguyên Tông tập hợp chuẩn bị rời tinh vực cấp năm sang tinh vực mới do Vô Cực Tông mở ra. Vương Lâm ngồi trong mật thất Quy Nguyên Tông dung hợp tâm thần với linh hồn Thiên Vận Tử trong Phong Tiên Ấn, khai thác năng lực dự đoán thiên địa cưỡng chế thôi diễn tương lai — nhìn thấy hàng loạt kịch bản đều kết thúc bằng cái chết (bị cặp mắt trên bầu trời hủy diệt, bỏ chạy vẫn bị bắt, hóa Cổ Thần chiến đấu với lão già áo bào trắng bị điểm chỉ mà chết). Hắn thi triển Tát Đậu Thành Binh với khẩu quyết đầy đủ, dung hợp hoàn toàn linh hồn Thiên Vận Tử thành nguyên thần, xác định có tu sĩ Đệ Tam Bộ cực kỳ hùng mạnh muốn mình chết. Cuối cùng hắn phá hủy thạch châu mô phỏng Thiên Nghịch triệu hồi thuật pháp tính toán thiên địa của Nghịch Hành Giả, dùng thân mình làm thiên địa thôi diễn ra đường sinh cơ duy nhất — hình ảnh một người tự xưng Lưu Kim Bưu, đạo hiệu Kim Bưu Tử."},{"chuong":1198,"tieuDe":"Ngươi Là Lưu Kim Bưu Sao?","tomTat":"Đệ tử Quy Nguyên Tông tập trung trên quảng trường sơn môn chờ rời Mạc La đại lục thì bất ngờ một ngọc giản phóng kim quang bay đến, phát khí tức Toái Niết đại viên mãn. Ngọc giản tự xưng là Lưu Kim Bưu (Kim Bưu Tử), đe dọa ba ngày trước có người thuê y giết toàn bộ Quy Nguyên Tông, đòi nộp tất cả túi trữ vật, còn dụ dỗ rằng y có quan hệ với tông chủ Vô Cực Tông. Vương Lâm trong mật thất nhận ra danh tự, thu linh hồn Thiên Vận Tử vào Phong Tiên Ấn nuốt vào miệng rồi xuất quan. Hắn dùng thần thức quét toàn đại lục theo khí tức ngọc giản, lần ra bản thể Lưu Kim Bưu — một lão già tu vi chỉ Âm Hư ẩn thân ở quán rượu đô thành phàm nhân phía nam, dùng ngọc bội trong suốt huyễn hóa nhật nguyệt phóng đại khí tức truyền âm xa mười vạn dặm. Vương Lâm hiện thân hỏi lạnh, lão già hoảng sợ phun máu bỏ chạy nhưng ngọc bội hộ thân phát hào quang chặn đứng hai đòn nguyên lực thiên địa cấp Toái Niết, khiến lão lông tóc không tổn hại. Vương Lâm kinh ngạc trước uy lực phòng thủ kỳ dị của ngọc bội, tiếp tục truy kích. Cuối cùng hắn bấm pháp quyết huyễn hóa cấm chế số lượng cực lớn tạo vòng vây khốn bao phủ thiên địa nhắm vào ngọc bội."},{"chuong":1199,"tieuDe":"Thiên Nghịch Biến Mất","tomTat":"Vương Lâm thi triển cấm chế phong tỏa ngọc bội của Lưu Kim Bưu, triệu sấm sét và dùng đoản kiếm diệt bảy con rết huyễn hóa từ ngọc bội. Ngọc bội phóng ra con rết ngàn trượng cực mạnh, Lưu Kim Bưu hô hào thôn phệ Vương Lâm, nhưng Vương Lâm dùng tiếng rống Cổ Thần (huyết mạch vương tộc gần lục tinh) đánh tan hoàn toàn. Vương Lâm chụp lấy ngọc bội, ngọc bội dung nhập vào thân thể, soi sáng lẫn nhau với hạt châu Thiên Nghịch trong nguyên thần, Thiên Nghịch hút ngọc bội vào rồi ầm ầm tan vỡ biến mất — Vương Lâm cảm nhận bản thân đã trở thành Thiên Nghịch. Một đoạn ký ức từ ngọc bội lộ ra: ngọc bội bị chôn ngàn năm dưới đất, tám con rết hấp thu khí tức rồi tử vong hóa khí linh nhưng chỉ điều khiển được một phần ngàn sức mạnh, vạn năm sau Lưu Kim Bưu vô tình phun máu lên mà nhặt được. Lưu Kim Bưu mất liên lạc ngọc bội, quỳ gối cầu xin tha mạng. Vương Lâm ném Lưu Kim Bưu vào không gian trữ vật giao cho Hứa Lập Quốc dạy bảo, nhận xét tội lão không đáng chết nhưng đã lừa cả Quy Nguyên Tông. Hứa Lập Quốc trăm năm buồn chán trong túi trữ vật, nay nhận được con mồi thì hưng phấn xoa tay phóng tới."},{"chuong":1200,"tieuDe":"Không Còn Nhà","tomTat":"Vương Lâm phát hiện ngọc giản Lưu Kim Bưu và hạt châu Thiên Nghịch biến mất quỷ dị, con đường sống thôi diễn ra bị cắt đứt. Lữ Yên Phỉ dẫn toàn bộ đệ tử Quy Nguyên Tông rời đi qua trận pháp hướng tinh vực cấp bảy, Vương Lâm ở lại một mình, thề sớm muộn Đệ Tam Bộ phải cúi đầu. Ở Phá Thiên Tông tinh vực cấp chín, Lý Thiến Mai bị ba trưởng lão giam trong trận pháp theo lệnh sư tôn. Tông chủ tiết lộ Thần Tông đã hủy đại hội phân tông cấp tám, đại trưởng lão Thủy Đạo Tử điều tra Lữ Tử Hạo nhiều năm, nguy cơ bao phủ Vương Lâm cực lớn. Lý Thiến Mai dập đầu tạ ơn rồi dùng phương pháp tiêu đạo uy hiếp sư tôn, quyết đi tìm Vương Lâm. Sư tôn phá trận cho nàng đi nhưng tuyên bố đoạn tuyệt sư đồ, đánh tan nhục thể ba trưởng lão phản đối, tiết lộ Phá Thiên Tông mười vạn tám ngàn năm trước đã là nô tài Thần Tông. Lý Thiến Mai dập đầu sáu lần rồi hóa cầu vồng bay đi mang cảm giác đã không còn nhà. Song tuyến quay lại Vương Lâm tại Quy Nguyên Tông, hắn liên tục tế luyện phá phong ấn hai thanh đoản kiếm thế giới bảy màu, tạo ra trăm vạn bóng kiếm đen trắng thành gió kiếm kinh thiên động địa."},{"chuong":1201,"tieuDe":"Đợi Ngươi Đến","tomTat":"Vương Lâm cưỡng chế mở thêm ba phong ấn trên hai thanh đoản kiếm đen trắng (từ bốn lên bảy trong chín), dùng quy tắc chi tinh, lôi cầu, lửa lam, chiến ý và máu huyết Cổ Thần. Kiếm thu nhỏ thành trủy thủ, kiếm khí tăng lên 9.999.999 luồng. Nhận thấy không thể mở phong ấn thứ tám trong thời gian ngắn, hắn hút toàn bộ kiếm khí vào thân thể ngưng tụ lên ngón trỏ tay phải, hai kiếm hóa hai đồ đằng hình nai — uy lực nhất chỉ này khiến tu sĩ Thiên Nhân Suy Kiếp phải tránh xa. Rời Mạc La đại lục vì lo chiến đấu sẽ hại phàm nhân, hắn chọn một man hoang đại lục trong sương mù tinh không làm chiến trường. Nhớ lại kết quả dung hợp linh hồn Thiên Vận Tử cho thấy nguy cơ sinh tử chỉ còn bảy ngày, hắn thi triển cổ đại thần thông phân trăm phân thần nhờ Cổ Thần tinh thứ sáu có dấu hiệu khôi phục, kéo trăm man hoang đại lục về ghép thành trận pháp khổng lồ. Lần lượt bao phủ Phá Diệt Cấm, gọi Ngân Y nữ tử thi triển Sinh Tử Cấm, và tự mình đánh ra Tuế Nguyệt Cấm kết hợp Lưu Nguyệt nghịch chuyển. Đến ngày thứ năm tam đại cấm chế hoàn thành, Vương Lâm tuyên bố dù tu sĩ Đệ Tam Bộ cũng không dễ giết mình và vẫn còn nhiều thủ đoạn chờ kẻ địch đến."},{"chuong":1202,"tieuDe":"Xạ Thần Xa Lại Tái Hiện!","tomTat":"Chỉ còn hai ngày trước khi kẻ giết từ Đệ Tam Bộ tiến đến, Vương Lâm hoàn tất bốn đòn tấn công cực mạnh sau năm ngày chuẩn bị liên tục. Đòn thứ nhất là ngàn vạn kiếm khí ngưng tụ thành một chỉ. Đòn thứ hai dùng tam đại cấm chế của hắn và Ngân Y Nữ Tử dung hợp trên gần trăm man hoang đại lục, luyện hóa thành trận pháp hủy diệt ngang hoặc vượt pháp bảo Thông Thiên mà Viêm Lôi Tử từng luyện. Đòn thứ ba thi triển Phù Văn Thuật hút toàn bộ máu thịt tinh hoa mãnh thú trên trăm đại lục hóa thành Phù Văn huyết sắc có uy áp đủ diệt Toái Niết hậu kỳ, tiếng kêu thảm thiết truyền khắp tinh vực cấp năm. Đòn thứ tư khai phong ấn hoàn toàn hai chiếc Xạ Thần Xa — chiếc thứ nhất hóa chiến xa Lôi thú mấy ngàn trượng có trường mâu vạn trượng bùng sấm sét, chiếc thứ ba mạnh nhất hóa kén ngàn trượng rồi lộ chiến xa bảy gai sắc phát sáng bảy màu, chỉ còn luồng phong ấn cuối cùng chưa phá được. Cuối cùng trong mười hai canh giờ còn lại, Vương Lâm lấy hai đoạn Thiết kiếm gãy, nuốt vào miệng bắt đầu tế luyện vết máu trong nguyên thần — loại máu cùng loại Cổ Thần nhưng theo Thanh Long Thánh Hoàng có chút giống máu thiên đạo. Tâm thái Vương Lâm kiên định, thân là nghịch tu vương tộc Cổ Thần, hắn chấp nhận chết trận chứ không khuất nhục."},{"chuong":1203,"tieuDe":"Tiến Đến","tomTat":"Lý Thiến Mai phóng đi cô độc trong tinh không với giọt lệ trên mặt, còn Mộc Băng Mi bị trận pháp Thần Tông vây khốn trong cung điện theo lệnh đại trưởng lão mà không hay biết Vương Lâm đang lâm nguy. Vương Lâm dùng mười hai canh giờ ép ba phần vết máu từ Thiết kiếm ra rồi nhập định chờ kẻ địch. Thủy Đạo Tử thuộc Đệ Tam Bộ xuất hiện, thò cánh tay khổng lồ già cỗi từ vòng xoáy sương mù chộp xuống, phong ấn hoàn toàn nguyên lực thiên địa. Vương Lâm phản kích bằng Ngàn vạn kiếm khí đạt mức viên mãn chín trăm chín mươi vạn luồng kèm hai đồ đằng hình nai, rồi cho kiếm khí tự hủy bên trong lòng bàn tay, chỉ gây được một điểm máu duy nhất trên tay Đệ Tam Bộ nhưng đó vẫn là thương tích thực sự. Thủy Đạo Tử hiện bản thể là đồng tử tóc trắng, nuốt máu Vương Lâm xác nhận hắn không phải chuyển thế trùng tu, rồi dùng Đại Tự Tại Băng Hội Đạo phá tan toàn bộ Phù Văn huyết sắc. Vương Lâm lần đầu dung hợp tam đại cấm chế phong tỏa thiên địa, thân thể và nguyên thần của Thủy Đạo Tử, dù thiếu cấm chế thứ tư phong hồn và bị lão lần lượt phá giải nhưng vẫn khiến lão khựng lại một khoảnh khắc. Chớp lấy khoảnh khắc đó, Vương Lâm khai Xạ Thần Xa phóng trường mâu cùng cầu vồng gai nhọn bảy màu lao thẳng tới, lần đầu tiên khiến vẻ mặt Thủy Đạo Tử biến đổi."},{"chuong":1204,"tieuDe":"Bốn Cảnh Giới Của Đệ Tam Bộ","tomTat":"Nguồn gốc Xạ Thần Xa được hé lộ: do Đa Bảo Thượng Nhân, một vị tiên điên khùng trên Vũ Tiên giới, hao tốn toàn bộ sở học và tuổi thọ để chế tạo, mong tạo pháp khí giết sạch thần linh — nhưng bỏ mình trong đại kiếp nạn tiên giới khi pháp khí chưa hoàn thành. Trường mâu vạn trượng của Xạ Thần Xa phóng về phía Thủy Đạo Tử nhưng bị Đại Tự Thiết Cát Đạo cắt đôi, man hoang đại lục tan vỡ, Vương Lâm thất khiếu chảy máu. Luồng cầu vồng bảy màu — pháp khí mạnh nhất — xuyên qua phá khe nứt không gian và hai đầu quỷ Toái Niết, buộc Thủy Đạo Tử phải lui bước. Vương Lâm hóa thân Cổ Thần tổng lực thi triển mọi thần thông nhưng tất cả bị Định Thần Thuật của Thủy Đạo Tử đóng băng. Thủy Đạo Tử tiết lộ bốn cảnh giới Đệ Tam Bộ — Không Niết, Không Linh, Không Huyền, Không Kiếp — và cần Không Linh mới mở hết phong ấn Xạ Thần Xa. Lão dùng vòng xoáy mi tâm cưỡng đoạt Xạ Thần Xa. Vương Lâm không cam lòng trước khoảng cách tu vi, quyết tâm dùng ba sát chiêu cuối cùng dù chết cũng khiến Thủy Đạo Tử trả giá."},{"chuong":1205,"tieuDe":"Phản Kích","tomTat":"Sâu trong Phong giới, trên đại lục bay bổng đỏ sậm, một tượng đá bí ẩn tự xưng lão phu nói về quân cờ bị Thủy Đạo Tử giết, đặt nghi vấn về Phong giới Tôn Lão chuyển thế và hạt châu Thiên Nghịch. Ngoài chiến trường, Thủy Đạo Tử dùng Định Thần Thuật khống chế toàn bộ thiên địa khiến mọi thứ bất động rồi vỗ tay phá hủy Xạ Thần Xa (Lôi thú) đã theo Vương Lâm hơn nửa đời tu đạo. Vương Lâm chảy huyết lệ phát thệ sẽ giết Thủy Đạo Tử. Khi Thủy Đạo Tử muốn chiếm Xạ Thần Xa bảy màu, Bảo linh Không Linh tự hủy hóa cánh bướm tiêu tán, xa thành phế vật. Thủy Đạo Tử dùng tu vi xuyên thấu thân thể và nguyên thần Vương Lâm tìm Thiên Nghịch nhưng không thấy, cưỡng mở không gian trữ vật, phá hàng loạt pháp bảo, phát hiện kiếm hồn Hứa Lập Quốc, đàn Văn Thú khổng lồ và Tị Thiên Quan bảo vật tiên đế Thiểm giới. Khi Thủy Đạo Tử dọa lấy cô gái trong Tị Thiên Quan, Ngân Y Nữ Tử bất ngờ mở mắt đánh thẳng thần thức vào lão khiến tâm thần rối loạn. Vương Lâm chớp thời cơ thôn phệ huyết cầu Thiết kiếm phá Định Thần Thuật, phóng Đinh bảy màu (Thần Không Đinh của Chưởng Tôn) thẳng về phía mi tâm Thủy Đạo Tử."},{"chuong":1206,"tieuDe":"Sống Lại","tomTat":"Thủy Đạo Tử hồi tưởng lai lịch Thất Thải Thần Không Đinh — 108 cây đinh do Chưởng Tôn luyện từ thiên thạch ngoại tinh thần, có đặc tính gặp mạnh cực mạnh và khắc chế Đệ Tam Bộ. Lão nhớ lại trận chiến xưa khi lão cùng vài Đệ Tam Bộ đánh lén Phong giới Tôn ở viễn cổ tiên vực, sau đó Chưởng Tôn viện cớ chiến sinh tử dùng 107 cây đinh. Trong khoảnh khắc Thủy Đạo Tử bị rối loạn tâm thần do nhiều yếu tố dồn dập, Vương Lâm bắn cây đinh bảy màu đâm vào mi tâm lão sâu một tấc. Huyết cầu trên Thiết kiếm hoàn toàn dung hợp vào nguyên thần Vương Lâm, giọt máu giống máu Cổ Thần cửu tinh, khiến toàn thân bốc cháy và phá được Định Thần Thuật. Vương Lâm điên cuồng ném Tam Xoa Kích hóa ác long tấn công. Thủy Đạo Tử thi triển Đại Tự Tại Tuyệt Không Đạo — hình thoi co rút từ ngàn vạn trượng xuống trăm trượng, nghiền nát hoàn toàn thân thể Vương Lâm, Tam Xoa Kích bị hủy diệt, linh hồn nó tử vong. Tuy nhiên hồng quang quỷ dị bùng lên, máu thịt nghịch chuyển ngưng tụ, Vương Lâm hoàn toàn tân sinh sống lại trong nháy mắt khiến Thủy Đạo Tử cực kỳ kinh hoàng."},{"chuong":1207,"tieuDe":"Một Trăm Quyền","tomTat":"Giọt máu bí ẩn trong nguyên thần phát hồng quang trọng sinh thân thể tan vỡ của Vương Lâm. Hắn hóa Cổ Thần thất tinh thi triển Cổ Thần thuật, dùng sinh cơ đổi lấy lực lượng thiên địa tung quyền liên tục vào Thủy Đạo Tử. Thủy Đạo Tử toàn bộ tu vi dồn lên mi tâm chống Thất Thải Thần Không Đinh nên lực chuyển xuống tay phải hạn chế, tay tê dại phải phun sương mù chống đỡ, đồng thời tiết lộ chiếc đinh là Thất Thải Thần Không Đinh của Chưởng Tôn. Sinh cơ bản thân Vương Lâm cạn kiệt ở quyền thứ 23 nhưng hắn ngộ ra chữ chiến là quyết tâm phản kháng dù biết chắc sẽ chết, vừa đánh vừa hồi cố toàn bộ đời tu đạo. Sương mù Thủy Đạo Tử bị phá tan ở khoảng quyền 64. Cuối cùng Vương Lâm kích hoạt Lưu Nguyệt nghịch chuyển năm ngàn năm tiêu hao tất cả nguyên lực lấy sinh cơ, hoàn thành trọn vẹn một trăm quyền mạnh nhất đời mình."},{"chuong":1208,"tieuDe":"Một Trăm Quyền!","tomTat":"Vương Lâm dồn toàn bộ tinh thần, nguyên lực, uy lực giọt máu Thiết kiếm và ý niệm tự sát vào một trăm quyền — đỉnh phong cả đời tu đạo hai ngàn năm — hóa hình bướm lao thẳng vào Thủy Đạo Tử. Thủy Đạo Tử dùng Thủy Đạo Thôn Hư Thuật chống đỡ nhưng bị sóng gợn cuốn ngược, đạo bào nổ tung, rỉ máu, mất kiểm soát Thất Thải Thần Không Đinh khiến đinh chui sâu ba tấc vào xương đầu, một phần hòa tan gây điên cuồng. Trái tim Vương Lâm vỡ tung, hai mắt mất sáng. Thủy Đạo Tử triển khai Đại Tự Tại Luân Hồi tạo Pháp Vi Luân định giết Vương Lâm trăm lần, nhưng một lão già bí ẩn dưới dạng phân thân gió xuất hiện, tự xưng từng được Phong Tôn phục vụ, bị đại tiên viễn cổ tiên vực phong ấn hóa đá hơn mười vạn năm, hiện mượn lực Văn Thú ở ngoài Thái Cổ Tinh Thần; lão dùng cánh tay gió phá tan Pháp Vi Luân và Định Thần Thuật cứu Vương Lâm. Thủy Đạo Tử tức giận hy sinh năm tỷ trong hai mươi tỷ Thủy Đạo môn đồ hóa lực hương hỏa Đệ Tam Bộ đập tan phân thân gió. Dù vậy lão già vẫn ra đòn cuối cùng dùng ngón tay gió ấn mạnh Thất Thải Thần Không Đinh xuống mi tâm Thủy Đạo Tử khiến thân thể lão khựng lại."},{"chuong":1209,"tieuDe":"Ba Luồng Bản Nguyên","tomTat":"Ngón tay phân thân của Vương Lâm xuất hiện bất ngờ khi Thủy Đạo Tử mất cảnh giác, ấn Thất Thải Thần Không Đinh đâm sâu năm tấc vào mi tâm lão, khiến lão kêu cứu chủ nhân. Bất diệt Phù Chiếu thứ ba — lần bảo hộ cuối cùng do Phong giới tôn sư ban — kích hoạt, phát kim quang tiêu tán cây đinh cứu mạng Thủy Đạo Tử, kèm giọng nói của Phong giới tôn sư khinh thường đạo làm người của lão rồi tiêu tán. Thủy Đạo Tử bị ý niệm điên cuồng của cây đinh chi phối nhưng dùng tu vi ép xuống, phóng thẳng về phía Vương Lâm. Đối mặt cái chết, Vương Lâm lĩnh ngộ tử khí bùng ra phá âm dương phá luân hồi, tự cảm ngộ bản nguyên thứ nhất — Sinh Tử. Tiếp đó hắn toái tinh, phá vỡ toàn bộ sáu Cổ Thần tinh điểm, cảm ngộ bản nguyên thứ hai — Nhân Quả. Quy tắc tinh do ý cảnh tan vỡ, sinh ra bản nguyên thứ ba — Thật Giả. Ba luồng bản nguyên là điều chưa từng có, vượt cả Chưởng Tôn và Thanh Lâm. Thủy Đạo Tử kinh hãi, nghi Vương Lâm là Đệ Tứ Bộ Đạp Thiên Đạo chuyển thế, bùng toàn lực Đệ Tam Bộ dung nhập tu chân tinh đánh thẳng xuống Vương Lâm."},{"chuong":1210,"tieuDe":"Ngọc Của Phong Giới","tomTat":"Thủy Đạo Tử kinh hãi khi nhận ra Vương Lâm sở hữu ba đạo bản nguyên (sinh tử, nhân quả, chân giả), quyết liều mạng giết bằng mọi giá bất chấp hủy mười lăm triệu môn đồ. Thực tế Vương Lâm còn ẩn chứa hai bản nguyên nữa — hỏa diễm (từ lửa Chu Tước ba lần lột xác) và lôi đình (từ cắn nuốt nửa Thái Cổ Lôi Long) — trở thành người có nhiều bản nguyên nhất từ cổ chí kim. Đối diện tử vong, Vương Lâm mang theo tình cảm cha mẹ, Uyển Nhi, Tư Đồ Nam, Thanh Thủy, quyết đồng quy vu tận: hủy năm đạo bản nguyên đánh ra đòn mạnh nhất đời, uy lực cận Đệ Tam Bộ, vượt Xạ Thần Xa, đủ giết Thanh Long Thánh Hoàng. Ngay khoảnh khắc hai bên va chạm, ngọc bội trên người Kim Bưu Tử — vốn đã dung nhập Thiên Nghịch và ẩn hoàn toàn trong nguyên thần Vương Lâm từ trước — bỗng xuất hiện tỏa kim quang vô hạn. Thủy Đạo Tử nhận ra đó là ngọc của Phong giới, vật duy nhất chủ nhân mang từ viễn cổ tiên vực xuống, nỗi sợ hãi vạn năm bùng lên khiến hắn mất hết ý chí phản kháng. Từ ngọc bội biến ảo ra ngón tay trong như ngọc, ấn Thất Thải Đinh xuống hai tấc, hoàn toàn chìm vào sâu trong đầu Thủy Đạo Tử."},{"chuong":1211,"tieuDe":"Đại Tạo Hóa Bắt Đầu","tomTat":"Thất Thải Đinh bị ngón tay chủ nhân Phong Giới đánh găm hoàn toàn vào mi tâm Thủy Đạo Tử, hòa tan thành chất lỏng bảy màu tràn ngập não bộ hắn, gây tổn thương hủy diệt không thể nghịch chuyển. Thủy Đạo Tử tuyệt vọng cười thảm, nhắc chủ nhân từng ban Bất Diệt Phù Chiếu miễn ba lần nguy cơ nay đã hết, tuyên bố không phục, tự xưng đứng đầu Thần Tông muốn thay mặt chủ nhân, rồi hạ lệnh mười lăm triệu môn đồ Thủy Đạo Môn tự bạo lấy hương hỏa đối kháng, phá hư không điên cuồng bỏ chạy biến mất trong tinh không. Vương Lâm thương thế cực kỳ nghiêm trọng, sinh cơ dùng hết, tóc bạc tang thương hóa lão già; Thiên Nghịch châu hòa tan tràn ngập thân thể, ngọc bội mô phỏng Thiên Nghịch dung nhập mi tâm, điểm sáng từ tam xoa kích vỡ vụn ngưng tụ tay phải, Thất Thải Hồ Điệp từ Xạ Thần Xa và hai con nai đen trắng từ đoản kiếm hắc bạch lần lượt dung nhập vào người — dưới lực lượng Thiên Nghịch hắn biến thành tượng đá mất hết thần thông, trôi nổi giữa tinh vực cấp năm sụp đổ. Một nữ tử bí ẩn tới chiến trường nước mắt chảy dài, được giọng nói già nua bí ẩn trong tinh không dạy phương pháp cứu Vương Lâm nhưng phải trả giá rất đắt. Sau ba mươi ngày tìm kiếm, nữ tử tìm thấy tượng đá, ôm mang tới đại lục hoang dã sâu trong Vân Hải, mỗi ngày cắn đầu ngón tay lấy máu tươi nhuộm toàn thân tượng đá."},{"chuong":1212,"tieuDe":"Phong Giới Tôn Sư","tomTat":"Hồn phách Vương Lâm rơi vào thế giới bên trong Thiên Nghịch châu sau trận chiến với Thủy Đạo Tử, lang thang mê man nhiều năm giữa sương mù ngũ hành. Huyết quang đỏ như máu liên tục từ bốn phương dung nhập vào hồn phách, xua tan giá lạnh, giúp hắn dần tỉnh táo và thực chất hóa. Trí nhớ thức tỉnh, Vương Lâm nhớ lại trận chiến, suy đoán chủ nhân Thủy Đạo Tử chính là Phong Giới Tôn Sư — tôn sư của Phong giới kiêm chủ nhân đời trước Thiên Nghịch châu, đồng thời hiểu lý do đồng tử tóc trắng tự sát. Giọng nói nỉ non tự xưng chủ nhân Phong giới vang lên dẫn đường, Vương Lâm tìm thấy cánh cửa đá thông thiên khổng lồ và quyết định bước vào. Song song đó, tại đại lục hoang dã Vân Hải, Lý Thiến Mai (Lý Oánh Chi) suốt bốn năm không rời nửa bước, rạch tay lấy máu nuôi dưỡng bức tượng đá trong suốt, tần suất tăng từ một lần lên bốn lần mỗi ngày khiến cánh tay héo khô, sắc mặt tái nhợt. Huyết quang trên tượng đá đang dần tiêu tan, tương ứng với huyết quang trong Thiên Nghịch ngày càng yếu ớt."},{"chuong":1213,"tieuDe":"Lai Lịch Hạt Châu Thiên Nghịch","tomTat":"Vương Lâm bước vào cánh cửa thông thiên bên trong Thiên Nghịch, đến một tinh không có cây đại thụ khổng lồ đang chết dần. Âm thanh già nua từ trong đại thụ tự xưng là chủ nhân Phong giới, đạo tiên Viễn Cổ Tiên Vực nội giới, tên đã quên. Tôn sư kể toàn bộ bí mật: xưa kia Thái Cổ Tinh Thần không phân chia, Viễn Cổ Tiên Vực thống lĩnh vạn tộc, nhưng chí bảo Thiên Nghịch (la bàn từ ngoài tinh không) gây kịch biến phân chia thành giới nội và giới ngoại, Tiên Hoàng bị trọng thương bế quan, bốn Tiên Phi thống lĩnh giới ngoại nhòm ngó giới nội. Thiên Nghịch châu ở trung tâm la bàn, trước tôn sư còn có hai chủ nhân là tu sĩ ngoài tinh không, phá giải bí mật có thể tìm tới Thái Cổ Thần Cảnh. Tôn sư bị đạo nô Thủy Đạo Tử đánh lén và người giới ngoại liên thủ diệt thân thể, phải ẩn vào Thiên Nghịch tồn tại nhờ bổn mạng Niết Kiếp bảo vật. Tôn sư đề nghị Vương Lâm kế tục làm tôn sư Phong giới, thủ hộ giới nội đợi Tiên Hoàng thức tỉnh, hứa có thể cứu sống Lý Uyển Nhi. Vương Lâm trong lòng từ chối vì không muốn số mạng phụ thuộc kẻ khác nhưng không nói thẳng. Tôn sư dùng lực lượng Thái Cổ Tinh Thần hóa lạc ấn đóng vào hồn phách Vương Lâm giúp tiến vào đạo cảnh, sau đó hoàn toàn tiêu tán. Hai năm trôi qua, tổng cộng sáu năm từ khi Vương Lâm hóa tượng đá, Lý Thiến Mai vẫn kiên trì bôi máu tươi lên tượng đá mỗi ngày, dung nhan bệnh tật tiều tụy như đóa hoa đang héo tàn."}];
